    return (window.__YX83_SHIP_LINE_META__||{})[k1] || (window.__YX83_SHIP_LINE_META__||{})[k2] || (window.__YX82_SHIP_LINE_META__||{})[k1] || (window.__YX82_SHIP_LINE_META__||{})[k2] || {};
