        sel.innerHTML='<option value="">此客戶無總單/訂單，請選擇庫存商品</option>'+items.map((it,i)=>`<option value="${i}">庫存｜${esc(it.material||it.product_code||'未填材質')}｜${esc(it.product_text||'')}｜${itemQty(it)}件</option>`).join('');
