      const customer=shortCustomer(it.customer_name||'未指定客戶');
      const product=itemText(it);
      const k=customer;
      if(!map.has(k)) map.set(k,{customer,terms:[],products:[]});
      const g=map.get(k);
      g.terms.push(String(qty(it)||1));
