      if(btn && btn.tagName === 'BUTTON'){ btn.disabled = true; btn.dataset.oldText = btn.textContent; btn.textContent = '復原中…'; }
      const d = await api('/api/undo-last', {method:'POST', body:JSON.stringify({})});
      toast(d.message || d.summary || '已復原上一筆', 'ok');
