  function sourceKey(){ return moduleKey() === 'master_order' ? 'master_order' : moduleKey() === 'orders' ? 'orders' : moduleKey() === 'ship' ? 'ship' : moduleKey(); }
  function sourceTitle(s){ return s === 'orders' ? '訂單' : s === 'master_order' ? '總單' : s === 'inventory' ? '庫存' : '商品'; }
