    let detail = $('yx144-warehouse-detail-panel');
    if (!detail) { detail = d.createElement('div'); detail.id = 'yx144-warehouse-detail-panel'; detail.className = 'yx144-warehouse-detail-panel'; }
    const meta = $('warehouse-modal-meta');
