      ta.dispatchEvent(new Event('input', {bubbles:true}));
      if (added) toast(`已加入 ${added} 筆商品`, 'ok');
      if (skipped) toast(`已阻止 ${skipped} 筆同尺寸+材質重複商品`, 'warn');
